package com.ansh.motoverse.service;
import com.ansh.motoverse.model.*; import com.ansh.motoverse.repository.*; import org.springframework.stereotype.Service; import java.math.BigDecimal; import java.util.List;
@Service public class BookingService { private final BookingRepository bookingRepository; private final VehicleRepository vehicleRepository; public BookingService(BookingRepository bookingRepository,VehicleRepository vehicleRepository){this.bookingRepository=bookingRepository;this.vehicleRepository=vehicleRepository;} public Booking createBooking(BookingRequest request){ Vehicle vehicle=vehicleRepository.findById(request.getVehicleId()).orElseThrow(()->new IllegalArgumentException("Vehicle not found")); if(!vehicle.isAvailable()) throw new IllegalStateException("Vehicle is not available for booking"); BigDecimal totalAmount=vehicle.getPricePerDay().multiply(BigDecimal.valueOf(request.getRentalDays())); return bookingRepository.save(new Booking(vehicle,request.getCustomerName(),request.getCustomerEmail(),request.getRentalDays(),totalAmount)); } public List<Booking> getAllBookings(){return bookingRepository.findAll();} }
